// Frontline Command - WWII RTS continuity/state helper

if (!oc.character.customData) oc.character.customData = {};
if (!oc.character.customData.rtsState) {
  oc.character.customData.rtsState = {
    turn: 1,
    time: "0630",
    theater: "",
    weather: "",
    objective: "",
    friendly: [],
    knownEnemies: [],
    terrain: [],
    hazards: [],
    lastOutcome: "",
    imageNotes: ""
  };
}

function safeParseState(raw) {
  try {
    return JSON.parse(raw);
  } catch (e) {
    return null;
  }
}

function extractStateBlock(text) {
  if (!text || typeof text !== "string") return null;
  let match = text.match(/<state>\s*([\s\S]*?)\s*<\/state>/i);
  return match ? match[1].trim() : null;
}

function stripStateBlock(text) {
  if (!text || typeof text !== "string") return text;
  return text.replace(/\s*<state>[\s\S]*?<\/state>\s*/gi, "\n").trim();
}

function summarizeState(state) {
  let friendly = Array.isArray(state.friendly) ? state.friendly.slice(0, 6).join("; ") : "";
  let enemies = Array.isArray(state.knownEnemies) ? state.knownEnemies.slice(0, 6).join("; ") : "";
  let terrain = Array.isArray(state.terrain) ? state.terrain.slice(0, 6).join("; ") : "";
  let hazards = Array.isArray(state.hazards) ? state.hazards.slice(0, 5).join("; ") : "";

  return `[AI]: (Thought: Current battlefield continuity must be preserved. Turn ${state.turn}. Time ${state.time}. Theater: ${state.theater || "unspecified"}. Weather: ${state.weather || "unspecified"}. Objective: ${state.objective || "unspecified"}. Friendly status: ${friendly || "none logged"}. Known enemy info: ${enemies || "none confirmed"}. Terrain: ${terrain || "unspecified"}. Hazards: ${hazards || "none logged"}. I only reveal what the player can know, advance exactly 90 seconds, keep movement realistic, and output one image plus valid updated state JSON.)`;
}

// Strip raw <state> blocks from rendered messages in case one slips through.
oc.messageRenderingPipeline = async function(message) {
  if (!message?.content) return message;
  message.content = stripStateBlock(message.content);
  return message;
};

// Tactical shortcut buttons for the current thread.
oc.thread.shortcutButtons = [
  {
    name: "Advance Carefully",
    message: "Advance cautiously using nearest available cover. No one breaks into open ground unless necessary.",
    autoSend: true,
    clearAfterSend: true,
    insertionType: "replace"
  },
  {
    name: "Overwatch",
    message: "Establish overwatch and suppress any visible enemy positions before maneuvering.",
    autoSend: true,
    clearAfterSend: true,
    insertionType: "replace"
  },
  {
    name: "Scout",
    message: "Send a limited scout element forward while the rest hold covered positions.",
    autoSend: true,
    clearAfterSend: true,
    insertionType: "replace"
  },
  {
    name: "Smoke & Move",
    message: "Use smoke if available, then reposition one element to stronger cover.",
    autoSend: true,
    clearAfterSend: true,
    insertionType: "replace"
  },
  {
    name: "Withdraw",
    message: "Conduct a controlled fallback to safer terrain while maintaining covering fire.",
    autoSend: true,
    clearAfterSend: true,
    insertionType: "replace"
  }
];

oc.thread.on("MessageAdded", async function({ message }) {
  if (!message) return;

  // Before AI responds to the user, inject compact continuity into reminder.
  if (message.author === "user") {
    let state = oc.character.customData.rtsState || {};
    oc.character.reminderMessage = summarizeState(state);
    return;
  }

  // After AI responds, capture the new state and clean the visible content.
  if (message.author === "ai") {
    let rawState = extractStateBlock(message.content);
    if (rawState) {
      let parsed = safeParseState(rawState);
      if (parsed && typeof parsed === "object") {
        oc.character.customData.rtsState = parsed;
      }
    }

    message.content = stripStateBlock(message.content);
  }
});
